#!/usr/bin/env python3
# 简单的 Python 脚本测试

print("Hello from Python script")

# 基本数据类型
name = "World"
count = 5
pi = 3.14159

print(f"Hello, {name}!")
print(f"Count is: {count}")
print(f"Pi is: {pi}")

# 列表操作
numbers = [1, 2, 3, 4, 5]
print(f"Numbers: {numbers}")
print(f"Sum: {sum(numbers)}")
print(f"Average: {sum(numbers) / len(numbers)}")
